#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <float.h>

#include "kmeans.h"

// CUDA kernel for updating membership and partial sums
// We use flat arrays for partial_centers and partial_len to avoid pointer complexity
__global__ void kmeans_update_membership_cuda(
    float **feature,
    float **clusters,
    int *membership,
    int *partial_new_centers_len, // Flat: [nthreads * nclusters]
    float *partial_new_centers,   // Flat: [nthreads * nclusters * nfeatures]
    int npoints,
    int nclusters,
    int nfeatures,
    int nthreads,
    float *delta_ptr)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    // Determine virtual thread ID to map to partial arrays
    int global_id = blockIdx.x * blockDim.x + threadIdx.x;
    int tid = global_id % nthreads;

    // Find nearest cluster
    int index = 0;
    float min_dist = FLT_MAX;

    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        float *cluster_ptr = clusters[c];
        float *feature_ptr = feature[i];
        for (int f = 0; f < nfeatures; f++) {
            float diff = feature_ptr[f] - cluster_ptr[f];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = c;
        }
    }

    // Update membership and delta
    int old_membership = membership[i];
    if (old_membership != index) {
        atomicAdd(delta_ptr, 1.0f);
    }
    membership[i] = index;

    // Update partial centers using atomic operations
    // Index in flat partial_len: tid * nclusters + index
    int len_idx = tid * nclusters + index;
    atomicAdd(&partial_new_centers_len[len_idx], 1);

    // Index in flat partial_centers: (tid * nclusters + index) * nfeatures + f
    int base_idx = (tid * nclusters + index) * nfeatures;
    float *feature_ptr = feature[i];
    for (int f = 0; f < nfeatures; f++) {
        atomicAdd(&partial_new_centers[base_idx + f], feature_ptr[f]);
    }
}

int cluster(int      numObjects,      
            int      numAttributes,   
            float  **attributes,                  
            int      nclusters,
            float    threshold,       
            float ***cluster_centres 
            )
{
    int    *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    tmp_cluster_centres = kmeans_clustering(attributes,
                                            numAttributes,
                                            numObjects,
                                            nclusters,
                                            threshold,
                                            membership);      

    if (*cluster_centres) {
		free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;


	free(membership);

    return 0;
}

// Re-implementing kmeans_clustering with CUDA
float** kmeans_clustering(float **feature,    
                          int     nfeatures,
                          int     npoints,
                          int     nclusters,
                          float   threshold,
                          int    *membership) 
{
    int      i, j, k, n=0, loop=0;
    int     *new_centers_len;			
    float  **new_centers;				
    float  **clusters;					
    float    delta;

    // Use 1 virtual thread for simplicity with atomic operations, 
    // or match the original logic by using a small fixed number.
    // The original code used num_omp_threads. We'll use 1 to simplify the atomic reduction.
    int nthreads_cuda = 1; 

    // Allocate clusters
    clusters    = (float**) malloc(nclusters *             sizeof(float*));
    clusters[0] = (float*)  malloc(nclusters * nfeatures * sizeof(float));
    for (i=1; i<nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    // Initialize clusters
    for (i=0; i<nclusters; i++) {
        for (j=0; j<nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i=0; i<npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    new_centers    = (float**) malloc(nclusters *            sizeof(float*));
    new_centers[0] = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i=1; i<nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    // Partial arrays for CUDA (simulating 1 thread with atomic updates)
    // We allocate flat arrays for easier CUDA management
    int *partial_new_centers_len = (int*) calloc(nthreads_cuda * nclusters, sizeof(int));
    float *partial_new_centers = (float*) calloc(nthreads_cuda * nclusters * nfeatures, sizeof(float));

    // GPU Memory
    float **d_feature;
    float **d_clusters;
    int *d_membership;
    int *d_partial_len;
    float *d_partial_centers;
    float *d_delta;

    // Allocate device arrays for data
    float *d_feature_data;
    float *d_clusters_data;

    cudaMalloc(&d_feature_data, npoints * nfeatures * sizeof(float));
    cudaMalloc(&d_clusters_data, nclusters * nfeatures * sizeof(float));

    // Copy feature data (flatten)
    float *flat_feature = (float*)malloc(npoints * nfeatures * sizeof(float));
    for(i=0; i<npoints; i++) {
        memcpy(flat_feature + i*nfeatures, feature[i], nfeatures*sizeof(float));
    }
    cudaMemcpy(d_feature_data, flat_feature, npoints * nfeatures * sizeof(float), cudaMemcpyHostToDevice);
    free(flat_feature);

    // Setup device pointer arrays for 2D access simulation
    cudaMalloc(&d_feature, npoints * sizeof(float*));
    cudaMalloc(&d_clusters, nclusters * sizeof(float*));

    float **tmp_feature = (float**)malloc(npoints * sizeof(float*));
    for(i=0; i<npoints; i++) tmp_feature[i] = d_feature_data + i*nfeatures;
    cudaMemcpy(d_feature, tmp_feature, npoints * sizeof(float*), cudaMemcpyHostToDevice);
    free(tmp_feature);

    float **tmp_clusters = (float**)malloc(nclusters * sizeof(float*));
    for(i=0; i<nclusters; i++) tmp_clusters[i] = d_clusters_data + i*nfeatures;
    cudaMemcpy(d_clusters, tmp_clusters, nclusters * sizeof(float*), cudaMemcpyHostToDevice);
    free(tmp_clusters);

    cudaMalloc(&d_membership, npoints * sizeof(int));
    cudaMemcpy(d_membership, membership, npoints * sizeof(int), cudaMemcpyHostToDevice);

    cudaMalloc(&d_partial_len, nthreads_cuda * nclusters * sizeof(int));
    cudaMalloc(&d_partial_centers, nthreads_cuda * nclusters * nfeatures * sizeof(float));

    cudaMalloc(&d_delta, sizeof(float));
    cudaMemset(d_delta, 0, sizeof(float));

    do {
        delta = 0.0;
        cudaMemset(d_partial_len, 0, nthreads_cuda * nclusters * sizeof(int));
        cudaMemset(d_partial_centers, 0, nthreads_cuda * nclusters * nfeatures * sizeof(float));
        cudaMemset(d_delta, 0, sizeof(float));

        int threads_per_block = 256;
        int blocks = (npoints + threads_per_block - 1) / threads_per_block;

        // Launch kernel
        kmeans_update_membership_cuda<<<blocks, threads_per_block>>>(
            d_feature, d_clusters, d_membership,
            d_partial_len, d_partial_centers,
            npoints, nclusters, nfeatures,
            nthreads_cuda, d_delta
        );

        cudaDeviceSynchronize();

        // Copy delta back
        cudaMemcpy(&delta, d_delta, sizeof(float), cudaMemcpyDeviceToHost);

        // Copy partial results back to host for aggregation
        int *host_partial_len = (int*)malloc(nthreads_cuda * nclusters * sizeof(int));
        cudaMemcpy(host_partial_len, d_partial_len, nthreads_cuda * nclusters * sizeof(int), cudaMemcpyDeviceToHost);

        float *host_partial_centers = (float*)malloc(nthreads_cuda * nclusters * nfeatures * sizeof(float));
        cudaMemcpy(host_partial_centers, d_partial_centers, nthreads_cuda * nclusters * nfeatures * sizeof(float), cudaMemcpyDeviceToHost);

        // Aggregate on host
        for (i=0; i<nclusters; i++) {
            for (j=0; j<nthreads_cuda; j++) {
                new_centers_len[i] += host_partial_len[j * nclusters + i];
                for (k=0; k<nfeatures; k++) {
                    new_centers[i][k] += host_partial_centers[(j * nclusters + i) * nfeatures + k];
                }
            }
        }

        free(host_partial_len);
        free(host_partial_centers);

        // Update centers
        for (i=0; i<nclusters; i++) {
            for (j=0; j<nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0;   
            }
            new_centers_len[i] = 0;   
        }

        // Update GPU clusters for next iteration
        float *flat_clusters = (float*)malloc(nclusters * nfeatures * sizeof(float));
        for(i=0; i<nclusters; i++) {
            memcpy(flat_clusters + i*nfeatures, clusters[i], nfeatures*sizeof(float));
        }
        cudaMemcpy(d_clusters_data, flat_clusters, nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice);
        free(flat_clusters);

        // Update GPU pointer array for clusters
        for(i=0; i<nclusters; i++) tmp_clusters[i] = d_clusters_data + i*nfeatures;
        cudaMemcpy(d_clusters, tmp_clusters, nclusters * sizeof(float*), cudaMemcpyHostToDevice);

    } while (delta > threshold && loop++ < 500);

    // Cleanup GPU
    cudaFree(d_feature_data);
    cudaFree(d_feature);
    cudaFree(d_clusters_data);
    cudaFree(d_clusters);
    cudaFree(d_membership);
    cudaFree(d_partial_len);
    cudaFree(d_partial_centers);
    cudaFree(d_delta);

    // Copy final membership back
    cudaMemcpy(membership, d_membership, npoints * sizeof(int), cudaMemcpyDeviceToHost);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);
    free(partial_new_centers_len);
    free(partial_new_centers);

    return clusters;
}

